2. The Elegant sampleNextToken Implementation
This function is now responsible for handling temperature and the nucleus selection:

C++
#include <algorithm>
#include <cmath>
#include <numeric>
#include <random>

// Assuming m_topP is a private member variable of InferenceEngine (e.g., initialized to 0.9)
// and that you have a thread-safe random number generator available.

int32_t InferenceEngine::sampleNextToken(std::vector<float>& logits, double temperature, double topP)
{
    // 1. Convert Logits to Probabilities (Softmax)

    // Apply temperature scaling
    if (temperature > 0.0) {
        for (float& logit : logits) {
            logit /= temperature;
        }
    }
    
    // Find maximum logit for numerical stability (required before exponentiation)
    float maxLogit = *std::max_element(logits.begin(), logits.end());
    
    // Compute exponentiated logits and total sum (Softmax calculation)
    std::vector<float> probs(logits.size());
    float sumExp = 0.0f;
    for (size_t i = 0; i < logits.size(); ++i) {
        float expVal = std::exp(logits[i] - maxLogit);
        probs[i] = expVal;
        sumExp += expVal;
    }
    
    // Normalize to get final probabilities
    for (float& prob : probs) {
        prob /= sumExp;
    }

    // 2. Prepare for Top-P Selection

    // Create a vector of pairs: {probability, token_id}
    std::vector<std::pair<float, int32_t>> sortedTokens;
    for (size_t i = 0; i < probs.size(); ++i) {
        if (probs[i] > 0.0f) { // Ignore zero probability tokens
            sortedTokens.push_back({probs[i], static_cast<int32_t>(i)});
        }
    }

    // Sort by probability in descending order
    std::sort(sortedTokens.begin(), sortedTokens.end(), [](const auto& a, const auto& b) {
        return a.first > b.first;
    });

    // 3. Find the Nucleus (Top-P Threshold)

    float cumulativeProb = 0.0f;
    size_t nucleusSize = 0;

    for (const auto& tokenPair : sortedTokens) {
        cumulativeProb += tokenPair.first;
        nucleusSize++;
        
        // Stop when the cumulative probability exceeds topP (the nucleus)
        if (cumulativeProb >= topP) {
            break;
        }
    }
    
    // If the top token already exceeds P, the nucleus is just that token.
    // If the model is badly behaved, we might pick the entire vocab.
    if (nucleusSize == 0) {
        // Fallback: This should not happen if probabilities are normalized correctly
        return sortedTokens.front().second; 
    }

    // 4. Resample and Select the Next Token

    // Re-normalize the probabilities within the nucleus.
    float nucleusProbSum = 0.0f;
    for (size_t i = 0; i < nucleusSize; ++i) {
        nucleusProbSum += sortedTokens[i].first;
    }

    // Use a uniform random number in [0, nucleusProbSum)
    // NOTE: You must provide your own implementation of a thread-safe random float generator.
    float r = getRandomFloat(0.0f, nucleusProbSum); // Placeholder for your RNG call

    // Select the token based on the weighted random draw
    cumulativeProb = 0.0f;
    for (size_t i = 0; i < nucleusSize; ++i) {
        cumulativeProb += sortedTokens[i].first;
        if (r < cumulativeProb) {
            return sortedTokens[i].second;
        }
    }
    
    // Fallback in case of rounding errors, select the last token in the nucleus
    return sortedTokens[nucleusSize - 1].second;
}
